import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { markBulk } from '../store/slices/attendanceSlice';
import { attendanceAPI, schoolAPI } from '../services/api';
import toast from 'react-hot-toast';

var SC = {
  present: { label:'Present', short:'P',  bg:'#D1FAE5', c:'#065F46', color:'#10B981' },
  absent:  { label:'Absent',  short:'A',  bg:'#FEE2E2', c:'#991B1B', color:'#EF4444' },
  leave:   { label:'Leave',   short:'L',  bg:'#FEF3C7', c:'#92400E', color:'#F59E0B' },
  late:    { label:'Late',    short:'Lt', bg:'#EDE9FE', c:'#5B21B6', color:'#7C3AED' },
};
var PAGE = 10;

function downloadCSV(filename, headers, rows) {
  var lines = [headers].concat(rows).map(function(r) {
    return r.map(function(v) { return '"' + String(v).replace(/"/g,'""') + '"'; }).join(',');
  });
  var blob = new Blob(['\uFEFF' + lines.join('\r\n')], { type:'text/csv;charset=utf-8;' });
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
}

export default function Attendance() {
  var dispatch    = useDispatch();
  var reduxStudents = useSelector(function(s) { return s.admission.students; });
  var reduxClasses  = useSelector(function(s) { return s.admission.classes; });
  var records       = useSelector(function(s) { return s.attendance.records; });

  var today = new Date().toISOString().split('T')[0];

  var [dbStudents,  setDbStudents]  = useState([]);
  var [dbClasses,   setDbClasses]   = useState([]);
  var [isLiveDB,    setIsLiveDB]    = useState(false);
  var [selClass,    setSelClass]    = useState('');
  var [selClassId,  setSelClassId]  = useState('');
  var [selSec,      setSelSec]      = useState('');
  var [date,        setDate]        = useState(today);
  var [localAtt,    setLocalAtt]    = useState({});
  var [page,        setPage]        = useState(0);
  var [saved,       setSaved]       = useState(false);
  var [saving,      setSaving]      = useState(false);

  // Load from DB on mount
  var loadFromDB = useCallback(async function() {
    try {
      var clsRes = await schoolAPI.getClasses();
      var cls = clsRes.data.data || [];
      if (cls.length) { setDbClasses(cls); setIsLiveDB(true); }
    } catch {}
  }, []);

  useEffect(function() { loadFromDB(); }, [loadFromDB]);

  // When class changes, load that class attendance from DB
  var loadClassAttendance = useCallback(async function(classId, d) {
    if (!classId || !d) return;
    try {
      var res = await attendanceAPI.getClass({ classId: classId, date: d });
      var data = res.data.data || [];
      // pre-fill localAtt from DB data
      var updates = {};
      data.forEach(function(r) {
        if (r.status) updates[d + '|' + r.student_id] = r.status;
      });
      if (Object.keys(updates).length) {
        setLocalAtt(function(p) { return Object.assign({}, p, updates); });
      }
    } catch {}
  }, []);

  // Classes list — prefer DB, fallback to Redux
  var classList = useMemo(function() {
    if (dbClasses.length) return dbClasses;
    return reduxClasses.map(function(n) { return { id: null, name: n }; });
  }, [dbClasses, reduxClasses]);

  // Students list — prefer DB students, fallback to Redux
  var allStudents = useMemo(function() {
    if (isLiveDB && dbStudents.length) return dbStudents;
    return reduxStudents.map(function(s) {
      return { id: s.id, student_id: s.id, admission_no: s.adm, first_name: s.name.split(' ')[0], last_name: s.name.split(' ').slice(1).join(' '), cls: s.cls, sec: s.sec, class_name: s.cls, section_name: s.sec };
    });
  }, [isLiveDB, dbStudents, reduxStudents]);

  var sections = useMemo(function() {
    return Array.from(new Set(
      allStudents.filter(function(s) { return !selClass || (s.class_name || s.cls) === selClass; })
                 .map(function(s) { return s.section_name || s.sec; })
    )).filter(Boolean).sort();
  }, [allStudents, selClass]);

  var filtered = useMemo(function() {
    return allStudents
      .filter(function(s) {
        var cn = s.class_name || s.cls || '';
        var sn = s.section_name || s.sec || '';
        return (!selClass || cn === selClass) && (!selSec || sn === selSec);
      })
      .slice().sort(function(a,b) {
        var na = (a.first_name||'') + ' ' + (a.last_name||'');
        var nb = (b.first_name||'') + ' ' + (b.last_name||'');
        return na.localeCompare(nb);
      });
  }, [allStudents, selClass, selSec]);

  var totalPages   = Math.max(1, Math.ceil(filtered.length / PAGE));
  var pageStudents = filtered.slice(page * PAGE, (page+1) * PAGE);

  function keyOf(id) { return date + '|' + id; }

  function getStatus(id) {
    var k = keyOf(id);
    if (localAtt[k] !== undefined) return localAtt[k];
    if (records[k]  !== undefined) return records[k];
    return '';
  }

  function setStatus(id, status) {
    var next = Object.assign({}, localAtt);
    next[keyOf(id)] = status;
    setLocalAtt(next);
    setSaved(false);
  }

  function markAll(status) {
    var next = Object.assign({}, localAtt);
    filtered.forEach(function(s) { next[keyOf(s.student_id || s.id)] = status; });
    setLocalAtt(next);
    setSaved(false);
    toast.success('All ' + filtered.length + ' marked ' + SC[status].label);
  }

  var handleSave = async function() {
    setSaving(true);
    var final = {};
    filtered.forEach(function(s) {
      var id = s.student_id || s.id;
      final[keyOf(id)] = localAtt[keyOf(id)] || records[keyOf(id)] || 'present';
    });
    setLocalAtt(final);

    // Build attendance array for API
    var attendanceArr = Object.entries(final).map(function(entry) {
      var parts = entry[0].split('|');
      return { studentId: parts[1], status: entry[1] };
    });

    // Save to Redux store (local)
    dispatch(markBulk(Object.entries(final).map(function(entry) {
      var parts = entry[0].split('|');
      return { date: parts[0], studentId: parts[1], status: entry[1] };
    })));

    // Save to DB
    try {
      await attendanceAPI.mark({
        date: date,
        classId: selClassId || undefined,
        attendance: attendanceArr,
      });
      setSaved(true);
      toast.success('✅ Attendance saved to database!');
    } catch (err) {
      setSaved(true);
      if (err.response?.status === 409) {
        // Already marked — try updating
        try {
          await attendanceAPI.mark({
            date: date,
            classId: selClassId || undefined,
            attendance: attendanceArr,
            forceUpdate: true,
          });
          toast.success('✅ Attendance updated in database!');
        } catch {
          toast.success('✅ Attendance saved locally (DB update failed)');
        }
      } else {
        toast.success('✅ Attendance saved locally');
      }
    } finally {
      setSaving(false);
    }
  };

  var handleClassChange = function(name, id) {
    setSelClass(name);
    setSelClassId(id || '');
    setSelSec('');
    setPage(0);
    setSaved(false);
    if (id) loadClassAttendance(id, date);
  };

  function handleDownload() {
    var headers = ['S.No','Adm No','Student Name','Class','Section','Status','Date'];
    var rows = filtered.map(function(s, i) {
      var id   = s.student_id || s.id;
      var name = (s.first_name || '') + ' ' + (s.last_name || '');
      return [i+1, s.admission_no || s.adm || '', name.trim(), s.class_name || s.cls, s.section_name || s.sec, getStatus(id) || 'not marked', date];
    });
    downloadCSV('Attendance_' + (selClass||'All') + '_' + date + '.csv', headers, rows);
    toast.success('Downloaded!');
  }

  var summary = useMemo(function() {
    var c = { present:0, absent:0, leave:0, late:0, unmarked:0 };
    filtered.forEach(function(s) {
      var v = getStatus(s.student_id || s.id);
      if (v && c[v] !== undefined) c[v]++; else c.unmarked++;
    });
    return c;
  }, [filtered, localAtt, records, date]);

  var pct = filtered.length > 0 ? Math.round((summary.present / filtered.length) * 100) : 0;

  var inp = { padding:'9px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', background:'#fff', fontFamily:'inherit' };

  return React.createElement('div', null,
    // Header
    React.createElement('div', { style:{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:16,flexWrap:'wrap',gap:12} },
      React.createElement('div', null,
        React.createElement('h2', { style:{fontSize:20,fontWeight:700,color:'#111827'} }, 'Mark Attendance'),
        React.createElement('p', { style:{fontSize:12,color:'#6B7280',marginTop:2} },
          isLiveDB
            ? React.createElement('span', { style:{padding:'2px 8px',background:'#D1FAE5',color:'#065F46',borderRadius:10,fontSize:10,fontWeight:700} }, '🟢 Live DB — saves to PostgreSQL')
            : React.createElement('span', { style:{padding:'2px 8px',background:'#FEF3C7',color:'#92400E',borderRadius:10,fontSize:10,fontWeight:700} }, 'Demo mode — connect backend to save to DB')
        )
      ),
      React.createElement('div', { style:{display:'flex',gap:10,flexWrap:'wrap'} },
        React.createElement('button', { onClick:function(){markAll('present');}, style:{padding:'8px 14px',border:'1.5px solid #10B981',borderRadius:9,background:'#D1FAE5',color:'#065F46',fontSize:12,fontWeight:700,cursor:'pointer'} }, '✅ All Present'),
        React.createElement('button', { onClick:function(){markAll('absent');},  style:{padding:'8px 14px',border:'1.5px solid #EF4444',borderRadius:9,background:'#FEE2E2',color:'#991B1B',fontSize:12,fontWeight:700,cursor:'pointer'} }, '❌ All Absent'),
        React.createElement('button', { onClick:handleDownload, style:{padding:'8px 14px',border:'1.5px solid #1E40AF',borderRadius:9,background:'#DBEAFE',color:'#1E40AF',fontSize:12,fontWeight:700,cursor:'pointer'} }, '📥 Download CSV'),
        React.createElement('button', { onClick:handleSave, disabled:saving, style:{padding:'8px 20px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:saving?'not-allowed':'pointer'} }, saving ? '⏳ Saving…' : '💾 Save Attendance')
      )
    ),

    // Filters
    React.createElement('div', { style:{display:'flex',gap:12,marginBottom:16,flexWrap:'wrap',alignItems:'flex-end'} },
      React.createElement('div', { style:{display:'flex',flexDirection:'column',gap:5} },
        React.createElement('label', { style:{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'} }, 'Date'),
        React.createElement('input', { type:'date', value:date, onChange:function(e){setDate(e.target.value);setSaved(false);setPage(0);if(selClassId)loadClassAttendance(selClassId,e.target.value);}, style:inp })
      ),
      React.createElement('div', { style:{display:'flex',flexDirection:'column',gap:5} },
        React.createElement('label', { style:{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'} }, 'Class'),
        React.createElement('select', {
          value: selClass,
          onChange: function(e) {
            var opt = e.target.options[e.target.selectedIndex];
            handleClassChange(e.target.value, opt.getAttribute('data-id'));
          },
          style: Object.assign({},inp,{minWidth:140})
        },
          React.createElement('option', { value:'' }, 'All Classes'),
          classList.map(function(c) {
            return React.createElement('option', { key:c.id||c.name, value:c.name, 'data-id':c.id||'' }, c.name);
          })
        )
      ),
      React.createElement('div', { style:{display:'flex',flexDirection:'column',gap:5} },
        React.createElement('label', { style:{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'} }, 'Section'),
        React.createElement('select', {
          value: selSec,
          onChange: function(e) { setSelSec(e.target.value); setPage(0); setSaved(false); },
          style: Object.assign({},inp,{minWidth:110}),
          disabled: !sections.length
        },
          React.createElement('option', { value:'' }, 'All Sections'),
          sections.map(function(s) { return React.createElement('option', { key:s }, s); })
        )
      ),
      React.createElement('div', { style:{alignSelf:'flex-end',padding:'9px 14px',background:'#EDE9F8',borderRadius:9,fontSize:12,fontWeight:700,color:'#1E1B4B'} },
        filtered.length + ' students' + (selClass ? ' · ' + selClass + (selSec?'-'+selSec:'') : '')
      ),
      saved ? React.createElement('div', { style:{alignSelf:'flex-end',padding:'9px 14px',background:'#D1FAE5',borderRadius:9,fontSize:12,fontWeight:700,color:'#065F46'} }, '✅ Saved') : null
    ),

    // Main grid
    React.createElement('div', { style:{display:'grid',gridTemplateColumns:'1fr 270px',gap:16} },

      // Mark sheet
      React.createElement('div', { style:{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden',display:'flex',flexDirection:'column'} },
        // Headers
        React.createElement('div', { style:{display:'grid',gridTemplateColumns:'40px 1fr 90px 90px 90px 90px',padding:'10px 14px',background:'#F9FAFB',borderBottom:'1px solid #E5E7EB',alignItems:'center',gap:0} },
          React.createElement('div', { style:{fontSize:10,fontWeight:700,color:'#9CA3AF'} }, '#'),
          React.createElement('div', { style:{fontSize:10,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'} }, 'Student (A–Z)'),
          Object.entries(SC).map(function(entry) {
            var k=entry[0],v=entry[1];
            return React.createElement('div', { key:k, style:{textAlign:'center',fontSize:10,fontWeight:700,color:v.c,background:v.bg,padding:'3px 0',borderRadius:6,margin:'0 2px'} }, v.short + ' ' + v.label);
          })
        ),

        // Rows
        React.createElement('div', { style:{flex:1,minHeight:260} },
          filtered.length === 0
            ? React.createElement('div', { style:{padding:48,textAlign:'center',color:'#9CA3AF'} },
                React.createElement('div', { style:{fontSize:36,marginBottom:10} }, '👨‍🎓'),
                React.createElement('div', { style:{fontWeight:600,color:'#6B7280'} }, 'No students found'),
                React.createElement('div', { style:{fontSize:12,marginTop:4} }, 'Add students or change filter')
              )
            : pageStudents.map(function(s, idx) {
                var id  = s.student_id || s.id;
                var cur = getStatus(id);
                var nm  = ((s.first_name||'') + ' ' + (s.last_name||'')).trim() || s.name || '';
                var adm = s.admission_no || s.adm || '';
                var cn  = s.class_name || s.cls || '';
                var sn  = s.section_name || s.sec || '';
                return React.createElement('div', {
                  key: id,
                  style:{display:'grid',gridTemplateColumns:'40px 1fr 90px 90px 90px 90px',padding:'9px 14px',borderBottom:'0.5px solid #F3F4F6',alignItems:'center',background:idx%2?'#FAFAFA':'#fff',gap:0},
                  onMouseEnter:function(e){e.currentTarget.style.background='#F5F3FF';},
                  onMouseLeave:function(e){e.currentTarget.style.background=idx%2?'#FAFAFA':'#fff';}
                },
                  React.createElement('div', { style:{fontSize:11,fontWeight:600,color:'#9CA3AF'} }, page*PAGE+idx+1),
                  React.createElement('div', { style:{display:'flex',alignItems:'center',gap:8} },
                    React.createElement('div', { style:{width:30,height:30,borderRadius:8,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:12,fontWeight:700,color:'#1E1B4B',flexShrink:0} }, nm[0] || '?'),
                    React.createElement('div', null,
                      React.createElement('div', { style:{fontSize:12,fontWeight:600,color:'#111827'} }, nm),
                      React.createElement('div', { style:{fontSize:10,color:'#9CA3AF'} }, adm + (cn?' · '+cn+(sn?'-'+sn:''):''))
                    )
                  ),
                  Object.entries(SC).map(function(entry) {
                    var k=entry[0], v=entry[1];
                    var active = cur === k;
                    return React.createElement('div', { key:k, style:{display:'flex',alignItems:'center',justifyContent:'center'} },
                      React.createElement('div', {
                        onClick:function() { setStatus(id, k); },
                        style:{
                          cursor:'pointer',width:34,height:34,borderRadius:9,
                          display:'flex',alignItems:'center',justifyContent:'center',
                          background: active ? v.bg : 'transparent',
                          border: '2px solid ' + (active ? v.color : '#E5E7EB'),
                          transition:'all .15s'
                        }
                      },
                        React.createElement('span', { style:{fontSize:16,color:active?v.color:'#D1D5DB',lineHeight:1} }, active?'●':'○')
                      )
                    );
                  })
                );
              })
        ),

        // Pagination
        filtered.length > PAGE ? React.createElement('div', { style:{padding:'12px 16px',borderTop:'1px solid #E5E7EB',display:'flex',alignItems:'center',justifyContent:'space-between',background:'#F9FAFB',flexShrink:0} },
          React.createElement('span', { style:{fontSize:12,color:'#6B7280'} },
            'Showing ' + (page*PAGE+1) + '–' + Math.min((page+1)*PAGE,filtered.length) + ' of ' + filtered.length
